FUNCTION IsReflexive(R, A)
 FOR EACH a IN A
 IF (a, a) NOT IN R THEN
 RETURN FALSE
 RETURN TRUE
END FUNCTION

// Example: A = {1,2,3}, R = {(1,1),(2,2),(3,3)}
// Returns TRUE - reflexive

FUNCTION IsSymmetric(R)
 FOR EACH (a,b) IN R
 IF (b,a) NOT IN R THEN
 RETURN FALSE
 RETURN TRUE
END FUNCTION

// Example: R = {(1,2),(2,1),(2,3),(3,2)}
// Returns TRUE - symmetric

FUNCTION IsTransitive(R)
 FOR EACH (a,b) IN R
 FOR EACH (c,d) IN R
 IF b = c AND (a,d) NOT IN R THEN
 RETURN FALSE
 RETURN TRUE
END FUNCTION

// Example: R = {(1,2),(2,3),(1,3)}
// Returns TRUE - transitive

FUNCTION Compose(R, S) // R after S
 result = EMPTY SET
 FOR EACH (a,b) IN S
 FOR EACH (c,d) IN R
 IF b = c THEN
 ADD (a,d) TO result
 RETURN result
END FUNCTION

// Example: R = {(1,2)}, S = {(2,3)}
// Result: {(1,3)}

FUNCTION Inverse(R)
 result = EMPTY SET
 FOR EACH (a,b) IN R
 ADD (b,a) TO result
 RETURN result
END FUNCTION

